// src/services/auth.ts
async function authResponse(user) {
  const authUser = toAuthUser(user);
  if (user.role !== "CUSTOMER") {
    return { user: authUser };
  }
  if (!user.customerId) {
    throw new HTTPException(403, { message: "Customer account is not linked to a customer profile" });
  }
  const [customer] = await db.select().from(customers).where(eq(customers.id, user.customerId)).limit(1);
  if (!customer || customer.status !== "ACTIVE") {
    throw new HTTPException(403, { message: "Customer account is inactive" });
  }
  return {
    user: authUser,
    customer
  };
}
async function login(input) {
  const [user] = await db.select().from(users).where(eq(users.phone, input.phone)).limit(1);
  if (!user) {
    throw new HTTPException(401, { message: "Invalid phone or password" });
  }
  const passwordMatches = await bcryptjs_default.compare(input.password, user.password);
  if (!passwordMatches) {
    throw new HTTPException(401, { message: "Invalid phone or password" });
  }
  const token = await issueToken(user);
  const data = await authResponse(user);
  return {
    token,
    ...data
  };
}
async function getCurrentUser(userId) {
  const [user] = await db.select().from(users).where(eq(users.id, userId)).limit(1);
  if (!user) {
    throw new HTTPException(401, { message: "User not found" });
  }
  return authResponse(user);
}
async function changePassword(userId, input) {
  const [user] = await db.select().from(users).where(eq(users.id, userId)).limit(1);
  if (!user) {
    throw new HTTPException(401, { message: "User not found" });
  }
  const passwordMatches = await bcryptjs_default.compare(input.currentPassword, user.password);
  if (!passwordMatches) {
    throw new HTTPException(401, { message: "Current password is incorrect" });
  }
  await db.update(users).set({
    password: await bcryptjs_default.hash(input.newPassword, 12)
  }).where(eq(users.id, user.id));
  return { message: "Password changed successfully" };
}

// src/utils/http.ts
function ok(c, data, status = 200) {
  return c.json({ success: true, data }, status);
}
function fail(c, error, status = 400, details) {
  return c.json({ success: false, error, details }, status);
}

